# PAGE: SCHEMA EXPLORER  (page = "schema_explorer")  — Brief 04
# ══════════════════════════════════════════════════════════════════════════════

# Field types that cannot be queried with GROUP BY or NULL check
_SKIP_SAMPLE_TYPES = {"textarea", "encryptedstring", "base64", "anytype"}
# Field types that are always populated (exclude from cleanup)
_ALWAYS_POPULATED_TYPES = {"id", "autonumber", "formula", "rollup"}


def _bisect_valid_fields(sf, object_name: str, fields: list) -> list:
    """
    Recursively bisects a field list to identify and drop any fields that
    Salesforce rejects at query time (e.g. soft-deleted fields still visible
    in describe()).  Returns only the fields that can actually be selected.
    """
    if not fields:
        return []
    if len(fields) == 1:
        return []  # This single field caused the failure — drop it
    mid = len(fields) // 2
    out = []
    for half in (fields[:mid], fields[mid:]):
        try:
            sf.query(f"SELECT {', '.join(half)} FROM {object_name} LIMIT 1")
            out.extend(half)
        except Exception:
            out.extend(_bisect_valid_fields(sf, object_name, half))
    return out


def _get_live_field_names(sf, object_name: str) -> set | None:
    """
    Returns the set of field API names that can actually be queried on
    object_name right now.  Uses probe SELECT queries in batches of 400
    (well under the 20k-char SOQL limit) and binary-searches within any
    failing batch to isolate deleted/inaccessible fields.
    Returns None only if the object itself can't be queried at all, so
    callers can treat None as 'skip filtering' rather than 'no fields'.
    """
    # Get the full field list from describe so we know what to probe
    try:
        desc = getattr(sf, object_name).describe()
        all_fields = [f["name"] for f in desc.get("fields", [])]
    except Exception:
        return None

    BATCH = 400  # stays well under the 20k-char SOQL limit
    valid = []
    for i in range(0, len(all_fields), BATCH):
        chunk = all_fields[i : i + BATCH]
        try:
            sf.query(f"SELECT {', '.join(chunk)} FROM {object_name} LIMIT 1")
            valid.extend(chunk)
        except Exception:
            # At least one field in this batch is bad — bisect to find it
            valid.extend(_bisect_valid_fields(sf, object_name, chunk))

    return set(valid)


def _detect_integration_owner(api_name: str) -> tuple[str, str]:
    """Return (owner_label, pill_class) based on field prefix matching."""
    prefix = api_name.split("__")[0].lower() if "__" in api_name else ""
    for tool in ACTIVE_TOOLS:
        if prefix and tool.lower().startswith(prefix):
            return tool, "pill-active"
    for tool in RETIRED_TOOLS:
        if prefix and tool.lower().startswith(prefix):
            return tool, "pill-retired"
    if api_name.endswith("__c"):
        return "Custom", "pill-neutral"
    return "Standard", "pill-neutral"


def _load_field_inventory(object_name: str) -> pd.DataFrame:
    """Describe the object and return a DataFrame of all fields.

    Cross-checks describe() results against FieldDefinition so that fields
    which have been deleted (or are otherwise no longer queryable) in the org
    are silently excluded from the inventory.
    """
    sf = get_sf_connection()
    try:
        desc = getattr(sf, object_name).describe()
    except Exception:
        try:
            desc = sf.restful(f"sobjects/{object_name}/describe")
        except Exception as exc:
            st.error(f"Could not describe {object_name}: {exc}")
            return pd.DataFrame()

    live_fields = _get_live_field_names(sf, object_name)

    # ── Diagnostic: surface what the probe found ──────────────────────────────
    if live_fields is None:
        st.warning(
            "⚠️ Field validation probe failed — showing all fields from describe() "
            "without filtering. Check Salesforce API permissions."
        )
    else:
        describe_names = {f.get("name", "") for f in desc.get("fields", [])}
        dropped = describe_names - live_fields
        if dropped:
            st.info(
                f"🗑️ **{len(dropped)} field(s) excluded** — present in describe() but "
                f"rejected by live query probe (likely soft-deleted): "
                f"`{'`, `'.join(sorted(dropped))}`"
            )

    rows = []
    for f in desc.get("fields", []):
        api_name = f.get("name", "")
        # Skip fields that no longer exist in the org according to FieldDefinition
        if live_fields is not None and api_name not in live_fields:
            continue
        owner, _ = _detect_integration_owner(api_name)
        rows.append({
            "Label":       f.get("label", ""),
            "API Name":    api_name,
            "Type":        f.get("type", ""),
            "Length":      f.get("length") or f.get("precision") or "",
            "Owner":       owner,
            "PopRate":     None,   # filled in on demand
            "CreatedDate": "",
        })
    return pd.DataFrame(rows)


def _fetch_population_rates(
    object_name: str,
    fields: list[str],
    total_count: int,
    progress_bar=None,
    status_text=None,
    where_clause: str = "",
) -> dict[str, float]:
    """
    Run batched multi-field COUNT queries to get population rate per field.
    Each query counts up to 20 fields in a single SOQL call, reducing API
    round trips from N (one per field) to ceil(N/20).

    where_clause — optional SOQL condition (without the WHERE keyword) to
    restrict which records are counted, e.g. "Type IN ('Customer', 'Former Customer')".
    Both the denominator (total records) and numerator (populated records) use
    the same filter so the percentage is always relative to the filtered set.

    Validates the field list against live probe queries so that deleted fields
    are excluded rather than causing batch failures.
    """
    sf = get_sf_connection()
    live_fields = _get_live_field_names(sf, object_name)
    if live_fields is not None:
        fields = [f for f in fields if f in live_fields]
    rates = {}
    BATCH_SIZE = 20
    total_fields = len(fields)
    processed = 0
    where_sql = f" WHERE {where_clause}" if where_clause.strip() else ""

    for i in range(0, total_fields, BATCH_SIZE):
        batch = fields[i : i + BATCH_SIZE]

        # Build: SELECT COUNT(Field1) f0, COUNT(Field2) f1, ... FROM Object [WHERE ...]
        select_parts = [f"COUNT({fld}) f{j}" for j, fld in enumerate(batch)]
        soql = f"SELECT {', '.join(select_parts)} FROM {object_name}{where_sql}"

        try:
            res = sf.query(soql)
            record = res["records"][0] if res.get("records") else {}
            for j, fld in enumerate(batch):
                raw = record.get(f"f{j}", 0) or 0
                rates[fld] = round(raw / total_count * 100, 1) if total_count > 0 else 0.0
        except Exception:
            # If the batch fails (e.g. one field is non-aggregatable),
            # fall back to one query per field in this batch only.
            for fld in batch:
                try:
                    fld_where = f"{fld} != null"
                    if where_clause.strip():
                        fld_where = f"{fld_where} AND ({where_clause})"
                    r = sf.query(
                        f"SELECT COUNT(Id) cnt FROM {object_name} WHERE {fld_where}"
                    )
                    populated = r["records"][0]["cnt"]
                    rates[fld] = round(populated / total_count * 100, 1) if total_count > 0 else 0.0
                except Exception:
                    rates[fld] = None

        processed += len(batch)

        # Update progress if UI elements were passed in
        if progress_bar is not None:
            fraction = min(processed / total_fields, 1.0)
            progress_bar.progress(fraction)
        if status_text is not None:
            status_text.caption(
                f"Calculating population rates… {processed} of {total_fields} fields done."
            )

    return rates


def _get_picklist_fields_for_filter(object_name: str) -> list:
    """
    Return picklist field metadata for the Schema Explorer record-scope filter.
    Uses describe() only — no probe queries — so it is fast and safe to call
    before fields are loaded.  Results are cached for 5 minutes.

    Returns a list of dicts: [{name, label, values: [str]}]
    """
    sf = get_sf_connection()
    try:
        desc = getattr(sf, object_name).describe()
    except Exception:
        try:
            desc = sf.restful(f"sobjects/{object_name}/describe")
        except Exception:
            return []
    result = []
    for f in desc.get("fields", []):
        if f.get("type") not in ("picklist", "multipicklist"):
            continue
        active_vals = [
            pv["value"]
            for pv in (f.get("picklistValues") or [])
            if pv.get("active")
        ]
        if active_vals:
            result.append({
                "name":   f["name"],
                "label":  f["label"],
                "values": active_vals,
            })
    return result


def render_schema_explorer_page(dry_run_mode: bool, auto_backup: bool):
    """
    Schema Explorer — review active fields on any Salesforce object and
    measure data completion rates scoped to a specific record filter
    (e.g. customer and former-customer accounts).
    """
    st.subheader("📄 Schema Explorer")
    st.caption(
        "Review active fields on any Salesforce object. "
        "Set a record scope, load fields, then calculate completion rates."
    )

    sf = get_sf_connection()

    # ── All queryable objects ─────────────────────────────────────────────────
    try:
        all_objects = sorted(
            s["name"] for s in sf.describe()["sobjects"]
            if s.get("queryable") and s.get("createable")
        )
    except Exception:
        all_objects = ["Account", "Contact", "Opportunity", "Case", "Lead"]

    # ── Object selector + field search ───────────────────────────────────────
    col_obj, col_search = st.columns([2, 3])
    with col_obj:
        default_idx = all_objects.index("Account") if "Account" in all_objects else 0
        selected_object = st.selectbox(
            "Object", all_objects, index=default_idx, key="oe_object"
        )
    with col_search:
        field_search = st.text_input(
            "Search fields",
            placeholder="Filter by label or API name…",
            key="oe_search",
        )

    # ── View mode ─────────────────────────────────────────────────────────────
    view_mode = st.radio(
        "View",
        ["📋 All Fields", "🧹 Cleanup Candidates"],
        key="oe_view",
        horizontal=True,
        label_visibility="collapsed",
    )

    # ── Describe the selected object ──────────────────────────────────────────
    # Cached in session state so repeated Streamlit reruns don't hammer the API.
    # The Refresh button and Load Fields both clear this cache to fetch fresh data.
    _desc_key = f"_oe_desc_{selected_object}"
    if _desc_key not in st.session_state:
        try:
            st.session_state[_desc_key] = getattr(sf, selected_object).describe()
        except Exception:
            try:
                st.session_state[_desc_key] = sf.restful(
                    f"sobjects/{selected_object}/describe"
                )
            except Exception:
                st.session_state[_desc_key] = {"fields": []}
    obj_desc = st.session_state[_desc_key]

    # Build picklist field list from describe() — no probe queries needed
    picklist_fields = []
    for _f in obj_desc.get("fields", []):
        if _f.get("type") not in ("picklist", "multipicklist"):
            continue
        active_vals = [
            pv["value"]
            for pv in (_f.get("picklistValues") or [])
            if pv.get("active")
        ]
        if active_vals:
            picklist_fields.append({
                "name":   _f["name"],
                "label":  _f["label"],
                "values": active_vals,
            })
    label_to_pf = {pf["label"]: pf for pf in picklist_fields}

    # ── Record scope filter ───────────────────────────────────────────────────
    st.markdown("##### 🎯 Record scope")
    st.caption(
        "Population rates count only records that match this filter. "
        "Both the total record count and per-field counts use the same scope, "
        "so percentages are always relative to the filtered set."
    )

    # When the user switches to a different object, reset filter to defaults
    if selected_object != st.session_state.get("_oe_prev_obj"):
        st.session_state.pop("oe_scope_field", None)
        st.session_state.pop("oe_scope_values", None)
        st.session_state["_oe_prev_obj"] = selected_object

    scope_options = ["All records (no filter)"] + [pf["label"] for pf in picklist_fields]

    # Default filter field: Account Type when the object is Account
    if "oe_scope_field" not in st.session_state:
        st.session_state["oe_scope_field"] = next(
            (pf["label"] for pf in picklist_fields if pf["name"] == "Type"),
            "All records (no filter)",
        ) if selected_object == "Account" else "All records (no filter)"

    # Default filter values: Customer + Former Customer for Account Type
    if "oe_scope_values" not in st.session_state:
        _type_pf = next((pf for pf in picklist_fields if pf["name"] == "Type"), None)
        if selected_object == "Account" and _type_pf:
            st.session_state["oe_scope_values"] = [
                v for v in ("Customer", "Former Customer")
                if v in _type_pf["values"]
            ]

    col_sf, col_sv = st.columns([1, 2])
    with col_sf:
        scope_field_label = st.selectbox(
            "Filter records by",
            scope_options,
            key="oe_scope_field",
        )
    scope_pf = label_to_pf.get(scope_field_label)
    scope_values = []
    if scope_pf:
        with col_sv:
            scope_values = st.multiselect(
                "Include these values",
                scope_pf["values"],
                key="oe_scope_values",
                placeholder="Select one or more values…",
            )

    # Build WHERE clause from current selections
    if scope_pf and scope_values:
        _vals_sql = ", ".join(f"'{v}'" for v in scope_values)
        pop_where = f"{scope_pf['name']} IN ({_vals_sql})"
        st.caption(f"✅ Active scope: `{pop_where}`")
    else:
        pop_where = ""
        if scope_pf and not scope_values:
            st.caption("⚠️ No values selected — rates will cover ALL records")

    # Bust cached rates whenever the filter changes
    if pop_where != st.session_state.get("_oe_prev_where", ""):
        st.session_state["_oe_prev_where"] = pop_where
        st.session_state.pop("_oe_rates", None)

    # ── Action buttons (row 1: primary) ───────────────────────────────────────
    col_load, col_calc, col_ref = st.columns([1, 2, 1])
    with col_load:
        load_clicked = st.button("🔍 Load Fields", key="oe_load_btn")
    with col_calc:
        calc_clicked = st.button(
            "📊 Calculate Population Rates",
            key="oe_calc_btn",
            help="Runs batched COUNT queries scoped to the filter above.",
        )
    with col_ref:
        if st.button("↺ Refresh", key="oe_refresh_btn",
                     help="Clear all cached data and reload from Salesforce."):
            for _k in list(st.session_state.keys()):
                if _k.startswith("_oe_"):
                    del st.session_state[_k]
            st.rerun()

    # ── Action buttons (row 2: analysis) ──────────────────────────────────────
    col_activity, col_auto = st.columns(2)
    with col_activity:
        activity_clicked = st.button(
            "📅 Fetch Last Activity",
            key="oe_activity_btn",
            use_container_width=True,
            help="For each populated field, finds the most recent record modification date. Run after Calculate Population Rates.",
        )
    with col_auto:
        automation_clicked = st.button(
            "⚡ Analyze Automations",
            key="oe_auto_btn",
            use_container_width=True,
            help="Scans Workflow Rules and active Flows to detect which fields are touched by automation.",
        )

    # ── Load fields ───────────────────────────────────────────────────────────
    if load_clicked:
        # Force a fresh describe() — clear the cached copy
        st.session_state.pop(_desc_key, None)
        try:
            fresh_desc = getattr(sf, selected_object).describe()
        except Exception:
            try:
                fresh_desc = sf.restful(f"sobjects/{selected_object}/describe")
            except Exception as exc:
                st.error(f"Could not describe {selected_object}: {exc}")
                st.stop()
        st.session_state[_desc_key] = fresh_desc

        rows = []
        for _f in fresh_desc.get("fields", []):
            owner, _ = _detect_integration_owner(_f["name"])
            _ftype = _f.get("type", "").lower()
            # Classify population source from describe() metadata
            if _f.get("calculated") or _ftype == "formula":
                _src = "Formula"
            elif _f.get("autoNumber") or _ftype == "autonumber":
                _src = "Auto-number"
            elif not _f.get("updateable") and not _f.get("createable"):
                _src = "System"
            elif owner not in ("Standard", "Custom"):
                _src = "Integration"
            else:
                _src = "Editable"
            rows.append({
                "Label":        _f.get("label", ""),
                "API Name":     _f["name"],
                "Type":         _f.get("type", ""),
                "Owner":        owner,
                "Source":       _src,
                "PopRate":      None,
            })
        _new_df = pd.DataFrame(rows)
        _new_df["PopCount"]     = None   # filled in when rates are calculated
        _new_df["LastActivity"] = None   # filled in when last activity is fetched
        _new_df["Automation"]   = None   # filled in when automation analysis runs
        st.session_state["_oe_df"]     = _new_df
        st.session_state["_oe_object"] = selected_object
        st.session_state.pop("_oe_rates",        None)
        st.session_state.pop("_oe_counts",       None)
        st.session_state.pop("_oe_total",        None)
        st.session_state.pop("_oe_last_activity", None)
        st.session_state.pop("_oe_auto_map",      None)
        st.success(f"✅ Loaded {len(_new_df):,} fields on **{selected_object}**.")

    # ── Retrieve stored field data ────────────────────────────────────────────
    df: pd.DataFrame = st.session_state.get("_oe_df")
    stored_object: str = st.session_state.get("_oe_object", "")

    if df is None or df.empty:
        st.info("👆 Click **Load Fields** to begin.")
        return

    if stored_object and stored_object != selected_object:
        st.info(
            f"Showing fields for **{stored_object}**. "
            f"Click **Load Fields** to switch to {selected_object}."
        )

    # ── Calculate population rates ────────────────────────────────────────────
    if calc_clicked:
        # Exclude field types that cannot be used inside COUNT()
        queryable_fields = [
            row["API Name"]
            for _, row in df.iterrows()
            if row["Type"].lower() not in _SKIP_SAMPLE_TYPES
            and row["Type"].lower() not in _ALWAYS_POPULATED_TYPES
        ]

        # Get total record count for the scoped set
        count_soql = f"SELECT COUNT(Id) cnt FROM {stored_object}"
        if pop_where:
            count_soql += f" WHERE {pop_where}"
        try:
            total = sf.query(count_soql)["records"][0]["cnt"]
        except Exception as exc:
            st.error(f"Could not count {stored_object} records: {exc}")
            st.stop()

        scope_label = f" matching `{pop_where}`" if pop_where else " (all records)"
        st.caption(
            f"Calculating rates for **{len(queryable_fields)} fields** "
            f"across **{total:,} {stored_object}** records{scope_label}…"
        )

        where_sql = f" WHERE {pop_where}" if pop_where else ""
        rates: dict  = {}   # field → completion %
        counts: dict = {}   # field → raw populated record count
        BATCH = 20
        _prog = st.progress(0)
        _status = st.empty()

        for i in range(0, len(queryable_fields), BATCH):
            batch = queryable_fields[i : i + BATCH]
            select_parts = [f"COUNT({fld}) f{j}" for j, fld in enumerate(batch)]
            soql = f"SELECT {', '.join(select_parts)} FROM {stored_object}{where_sql}"
            try:
                rec = sf.query(soql)["records"][0]
                for j, fld in enumerate(batch):
                    raw = rec.get(f"f{j}") or 0
                    counts[fld] = raw
                    rates[fld]  = round(raw / total * 100, 1) if total else 0.0
            except Exception:
                # Batch failed — fall back to individual queries for this batch only
                for fld in batch:
                    try:
                        fld_filter = f"{fld} != null"
                        if pop_where:
                            fld_filter += f" AND ({pop_where})"
                        _r = sf.query(
                            f"SELECT COUNT(Id) cnt FROM {stored_object} WHERE {fld_filter}"
                        )
                        populated = _r["records"][0]["cnt"]
                        counts[fld] = populated
                        rates[fld]  = round(populated / total * 100, 1) if total else 0.0
                    except Exception:
                        counts[fld] = None
                        rates[fld]  = None

            done = min(i + BATCH, len(queryable_fields))
            _prog.progress(done / len(queryable_fields))
            _status.caption(f"{done} / {len(queryable_fields)} fields processed…")

        _prog.empty()
        _status.empty()

        updated_df = df.copy()
        updated_df["PopRate"] = updated_df["API Name"].map(lambda x, r=rates:  r.get(x))
        updated_df["PopCount"] = updated_df["API Name"].map(lambda x, c=counts: c.get(x))
        st.session_state["_oe_df"]     = updated_df
        st.session_state["_oe_rates"]  = rates
        st.session_state["_oe_counts"] = counts
        st.session_state["_oe_total"]  = total
        df = updated_df

    # ── Fetch last activity ───────────────────────────────────────────────────
    if activity_clicked:
        _la_counts = st.session_state.get("_oe_counts", {})
        # Only fetch dates for fields that are actually populated in this scope.
        # Skip booleans/id/system types — they're always set and the date adds no signal.
        _la_skip = _ALWAYS_POPULATED_TYPES | {"boolean"}
        _la_type_map = dict(zip(df["API Name"], df["Type"].str.lower()))
        _la_fields = [
            fld for fld, cnt in _la_counts.items()
            if cnt and cnt > 0 and _la_type_map.get(fld, "") not in _la_skip
        ]
        if not _la_fields:
            st.warning(
                "Run **Calculate Population Rates** first — "
                "last activity requires knowing which fields are populated."
            )
        else:
            _la_map: dict = {}
            _la_prog = st.progress(0)
            _la_status = st.empty()
            for _li, _fld in enumerate(_la_fields):
                _la_filter = f"{_fld} != null"
                if pop_where:
                    _la_filter += f" AND ({pop_where})"
                try:
                    _la_res = sf.query(
                        f"SELECT MAX(LastModifiedDate) maxd "
                        f"FROM {stored_object} WHERE {_la_filter}"
                    )
                    _la_map[_fld] = _la_res["records"][0].get("maxd")
                except Exception:
                    _la_map[_fld] = None
                _la_prog.progress((_li + 1) / len(_la_fields))
                if (_li + 1) % 10 == 0:
                    _la_status.caption(f"{_li + 1} / {len(_la_fields)} fields checked…")
            _la_prog.empty()
            _la_status.empty()

            _la_df = df.copy()
            _la_df["LastActivity"] = _la_df["API Name"].map(
                lambda x, la=_la_map: la.get(x)
            )
            st.session_state["_oe_df"]           = _la_df
            st.session_state["_oe_last_activity"] = _la_map
            df = _la_df

    # ── Analyze automations ───────────────────────────────────────────────────
    if automation_clicked:
        from urllib.parse import quote as _url_quote
        import json as _json

        _auto_map: dict = {}   # field API name → {"types": set, "names": list[str]}
        _auto_errors: list = []  # non-fatal warnings surfaced to user
        _auto_status = st.empty()

        # ══ 1. Workflow Rules ══════════════════════════════════════════════════
        # Compound fields (Metadata) cannot appear in Tooling SOQL SELECT — they
        # must be fetched per-record via REST GET.  So we do three steps:
        #   a) Get WorkflowRule IDs + names for this object
        #   b) Get WorkflowFieldUpdate IDs linked to those rules
        #   c) REST-GET each WorkflowFieldUpdate to read Metadata.field
        _auto_status.caption("Querying Workflow Rules…")
        _wf_rule_names: dict = {}  # rule_id → rule_name

        try:
            _wf_res = sf.restful(
                "tooling/query?q=" + _url_quote(
                    f"SELECT Id, Name FROM WorkflowRule "
                    f"WHERE TableEnumOrId = '{stored_object}'"
                )
            )
            _wf_rule_names = {r["Id"]: r.get("Name", "Unknown Rule")
                              for r in _wf_res.get("records", [])}
        except Exception as _ex:
            _auto_errors.append(f"WorkflowRule list failed: {_ex}")

        if _wf_rule_names:
            _auto_status.caption(
                f"Found {len(_wf_rule_names)} Workflow Rule(s) — fetching field updates…"
            )
            try:
                _id_csv = "', '".join(_wf_rule_names.keys())
                _wfu_res = sf.restful(
                    "tooling/query?q=" + _url_quote(
                        f"SELECT Id, WorkflowRuleId FROM WorkflowFieldUpdate "
                        f"WHERE WorkflowRuleId IN ('{_id_csv}')"
                    )
                )
                for _wfu in _wfu_res.get("records", []):
                    try:
                        _detail = sf.restful(
                            f"tooling/sobjects/WorkflowFieldUpdate/{_wfu['Id']}"
                        )
                        _field = (_detail.get("Metadata") or {}).get("field")
                        if _field:
                            _rule_name = _wf_rule_names.get(
                                _wfu.get("WorkflowRuleId"), "Unknown Rule"
                            )
                            _ent = _auto_map.setdefault(
                                _field, {"types": set(), "names": []}
                            )
                            _ent["types"].add("Workflow Rule")
                            _ent["names"].append(f"WF: {_rule_name}")
                    except Exception as _ex:
                        _auto_errors.append(
                            f"WorkflowFieldUpdate fetch failed ({_wfu.get('Id')}): {_ex}"
                        )
            except Exception as _ex:
                _auto_errors.append(f"WorkflowFieldUpdate query failed: {_ex}")

        # ══ 2. Active Flows ════════════════════════════════════════════════════
        # FlowVersion.Metadata is also a compound field — cannot be in SOQL SELECT.
        # Correct approach:
        #   a) Use FlowDefinitionView (standard SOQL, API v47+) to get active flows
        #      and their ActiveVersionId
        #   b) REST-GET each FlowVersion/{id} to retrieve the full Metadata JSON
        #   c) Text-search the JSON for each field API name
        _auto_status.caption("Fetching list of active Flows…")
        _flow_defs: list = []

        try:
            _fdv = sf.query(
                "SELECT Id, Label, ApiName, ActiveVersionId "
                "FROM FlowDefinitionView "
                "WHERE IsActive = true AND ActiveVersionId != null"
            )
            _flow_defs = _fdv.get("records", [])
        except Exception as _ex:
            _auto_errors.append(f"FlowDefinitionView query failed: {_ex}")
            # Fallback — Tooling API FlowDefinition
            try:
                _fdt = sf.restful(
                    "tooling/query?q=" + _url_quote(
                        "SELECT Id, Label, ApiName, ActiveVersionId "
                        "FROM FlowDefinition "
                        "WHERE Status = 'Active' AND ActiveVersionId != null"
                    )
                )
                _flow_defs = _fdt.get("records", [])
            except Exception as _ex2:
                _auto_errors.append(f"FlowDefinition fallback also failed: {_ex2}")

        _all_field_names = df["API Name"].tolist()
        _flow_cap = min(len(_flow_defs), 300)
        _flow_prog = st.progress(0, text=f"Scanning flows 0 / {_flow_cap}…")

        for _fi, _fd in enumerate(_flow_defs[:_flow_cap]):
            _vid    = _fd.get("ActiveVersionId")
            _flabel = _fd.get("Label", "Unknown Flow")
            if not _vid:
                continue
            try:
                _vdata     = sf.restful(f"tooling/sobjects/FlowVersion/{_vid}")
                _meta_text = _json.dumps(_vdata.get("Metadata") or {})
                for _fname in _all_field_names:
                    # Match "FieldName" as an exact JSON string, or .FieldName" for
                    # object-dot-field references like "$Record.FieldName__c"
                    if (f'"{_fname}"' in _meta_text
                            or f'.{_fname}"' in _meta_text
                            or f'.{_fname}.' in _meta_text):
                        _ent = _auto_map.setdefault(_fname, {"types": set(), "names": []})
                        _ent["types"].add("Flow")
                        _tag = f"Flow: {_flabel}"
                        if _tag not in _ent["names"]:
                            _ent["names"].append(_tag)
            except Exception as _ex:
                _auto_errors.append(
                    f"FlowVersion fetch failed for '{_flabel}' ({_vid}): "
                    f"{str(_ex)[:120]}"
                )
            _flow_prog.progress(
                (_fi + 1) / _flow_cap,
                text=f"Scanning flows {_fi + 1} / {_flow_cap}…",
            )

        _flow_prog.empty()
        _auto_status.empty()

        # ── Surface any non-fatal errors ──────────────────────────────────────
        if _auto_errors:
            with st.expander(
                f"⚠️ {len(_auto_errors)} warning(s) during automation scan — click to view"
            ):
                for _err in _auto_errors[:30]:
                    st.caption(_err)

        # ── Update Source and Automation columns ──────────────────────────────
        _auto_df = df.copy()
        for _fname, _info in _auto_map.items():
            _idx = _auto_df.index[_auto_df["API Name"] == _fname].tolist()
            if not _idx:
                continue
            _i     = _idx[0]
            _types = _info["types"]
            if "Workflow Rule" in _types and "Flow" in _types:
                _new_src = "Workflow + Flow"
            elif "Workflow Rule" in _types:
                _new_src = "Workflow Rule"
            else:
                _new_src = "Flow"
            if _auto_df.at[_i, "Source"] in ("Editable", "Integration"):
                _auto_df.at[_i, "Source"] = _new_src
            _auto_df.at[_i, "Automation"] = "; ".join(_info["names"][:5])

        st.session_state["_oe_df"]       = _auto_df
        st.session_state["_oe_auto_map"] = _auto_map
        df = _auto_df

        wf_count   = sum(1 for v in _auto_map.values() if "Workflow Rule" in v["types"])
        flow_count = sum(1 for v in _auto_map.values() if "Flow"          in v["types"])
        st.success(
            f"Automation scan complete — "
            f"**{wf_count}** field(s) touched by Workflow Rules, "
            f"**{flow_count}** field(s) referenced in active Flows "
            f"(scanned {_flow_cap} flows)."
        )

    # ── Apply field search and view mode ──────────────────────────────────────
    view = df.copy()
    if field_search:
        _mask = (
            view["Label"].str.contains(field_search, case=False, na=False)
            | view["API Name"].str.contains(field_search, case=False, na=False)
        )
        view = view[_mask]

    if view_mode == "🧹 Cleanup Candidates":
        _has_rates = view["PopRate"].notna().any()
        _zero_mask = (view["PopRate"] == 0.0) if _has_rates else pd.Series(False, index=view.index)
        _retired_mask = view["Owner"].isin(RETIRED_TOOLS)
        view = view[_zero_mask | _retired_mask]
        st.caption(
            f"{len(view)} cleanup candidates — 0% population or retired tool ownership."
        )

    # ── Metrics + table ───────────────────────────────────────────────────────
    _stored_total = st.session_state.get("_oe_total")

    # Build display — keep PopRate and PopCount as numerics so sorting is correct.
    # column_config handles the % and comma formatting in the rendered table.
    _has_counts   = "PopCount"     in view.columns and view["PopCount"].notna().any()
    _has_activity = "LastActivity" in view.columns and view["LastActivity"].notna().any()
    _has_source   = "Source"       in view.columns
    _has_auto     = "Automation"   in view.columns and view["Automation"].notna().any()

    _display_cols = ["Label", "API Name", "Type", "Owner"]
    if _has_source:
        _display_cols += ["Source"]
    if _has_auto:
        _display_cols += ["Automation"]
    if _has_counts:
        _display_cols += ["PopCount", "PopRate"]
    else:
        _display_cols += ["PopRate"]
    if _has_activity:
        _display_cols += ["LastActivity"]

    display = view[_display_cols].copy().rename(
        columns={"PopCount": "Populated", "PopRate": "Completion %", "LastActivity": "Last Activity"}
    )

    _col_config = {
        "Completion %": st.column_config.NumberColumn(
            "Completion %",
            format="%.1f%%",
            help="Percentage of records in scope where this field is populated",
        ),
    }
    if _has_counts:
        _col_config["Populated"] = st.column_config.NumberColumn(
            "Populated",
            format="%d",
            help="Number of records in scope where this field is populated",
        )
    if _has_activity:
        _col_config["Last Activity"] = st.column_config.DatetimeColumn(
            "Last Activity",
            format="DD MMM YYYY",
            help="Most recent date a record in scope had this field populated (MAX LastModifiedDate where field != null)",
        )
    if _has_source:
        _col_config["Source"] = st.column_config.TextColumn(
            "Source",
            help="Formula / Auto-number / System / Integration / Workflow Rule / Flow / Workflow + Flow / Editable",
        )
    if _has_auto:
        _col_config["Automation"] = st.column_config.TextColumn(
            "Automation",
            help="Workflow Rules and/or Flows that reference this field (writes, reads, or conditions)",
        )

    col_m1, col_m2, col_m3 = st.columns(3)
    with col_m1:
        st.metric("Fields shown", f"{len(display):,}")
    with col_m2:
        _rates_count = int(view["PopRate"].notna().sum())
        if _stored_total:
            st.metric("Records in scope", f"{_stored_total:,}")
        else:
            st.metric("Rates calculated", f"{_rates_count:,}" if _rates_count else "—")
    with col_m3:
        if _rates_count:
            _avg = view["PopRate"].dropna().mean()
            _scope_suffix = " (scoped)" if pop_where else ""
            st.metric(f"Avg completion{_scope_suffix}", f"{_avg:.0f}%" if not pd.isna(_avg) else "—")

    st.dataframe(display, use_container_width=True, hide_index=True, column_config=_col_config)

    # ── Export ────────────────────────────────────────────────────────────────
    st.markdown("---")
    _export_label = "cleanup_candidates" if view_mode.startswith("🧹") else "fields"
    _csv_bytes = display.to_csv(index=False).encode("utf-8")
    st.download_button(
        "📥 Export as CSV",
        data=_csv_bytes,
        file_name=f"{stored_object}_{_export_label}.csv",
        mime="text/csv",
        key="oe_export_csv",
    )


# ══════════════════════════════════════════════════════════════════════════════
# PAGE: REPORT & DASHBOARD SCANNER  (page = "report_scanner")  — Brief 07
# ══════════════════════════════════════════════════════════════════════════════

def _load_report_inventory() -> pd.DataFrame:
    """Query all reports. Paginate via queryMore."""
    sf = get_sf_connection()
    soql = (
        "SELECT Id, Name, FolderName, Owner.Name, Owner.IsActive, "
        "LastRunDate, CreatedDate, DeveloperName "
        "FROM Report ORDER BY LastRunDate ASC NULLS FIRST LIMIT 2000"
    )
    rows = []
    try:
        result = sf.query(soql)
        rows.extend(result.get("records", []))
        while not result.get("done", True):
            result = sf.query_more(result["nextRecordsUrl"], identifier_is_url=True)
            rows.extend(result.get("records", []))
    except Exception as exc:
        st.error(f"Could not load reports: {exc}")
        return pd.DataFrame()
    if not rows:
        return pd.DataFrame()
    df = pd.DataFrame([{
        "Id":          r.get("Id"),
        "Name":        r.get("Name"),
        "Folder":      r.get("FolderName") or "Unfiled",
        "Owner":       (r.get("Owner") or {}).get("Name", "Unknown"),
        "OwnerActive": (r.get("Owner") or {}).get("IsActive", True),
        "LastRunDate": r.get("LastRunDate"),
        "CreatedDate": r.get("CreatedDate"),
    } for r in rows])
    df["LastRunDate"] = pd.to_datetime(df["LastRunDate"], errors="coerce", utc=True)
    df["CreatedDate"] = pd.to_datetime(df["CreatedDate"], errors="coerce", utc=True)
    return df


def _load_dashboard_inventory() -> pd.DataFrame:
    sf = get_sf_connection()
    soql = (
        "SELECT Id, Title, FolderName, RunningUser.Name, LastViewedDate, CreatedDate "
        "FROM Dashboard ORDER BY LastViewedDate ASC NULLS FIRST LIMIT 2000"
    )
    rows = []
    try:
        result = sf.query(soql)
        rows.extend(result.get("records", []))
    except Exception as exc:
        st.warning(f"Could not load dashboards: {exc}")
        return pd.DataFrame()
    if not rows:
        return pd.DataFrame()
    df = pd.DataFrame([{
        "Id":            r.get("Id"),
        "Title":         r.get("Title"),
        "Folder":        r.get("FolderName") or "Unfiled",
        "RunningUser":   (r.get("RunningUser") or {}).get("Name", "Unknown"),
        "LastViewedDate": r.get("LastViewedDate"),
        "CreatedDate":   r.get("CreatedDate"),
    } for r in rows])
    df["LastViewedDate"] = pd.to_datetime(df["LastViewedDate"], errors="coerce", utc=True)
    df["CreatedDate"]    = pd.to_datetime(df["CreatedDate"], errors="coerce", utc=True)
    return df


def render_report_scanner_page(dry_run_mode: bool, auto_backup: bool):
    st.subheader("📊  Reports & Dashboards")
    st.caption(
        "Surface stale and orphaned reports and dashboards across the org. "
        "Read-only — no records are modified."
    )

    scanner_section = st.radio(
        "Section",
        ["📋  Report Inventory", "📊  Dashboard Inventory", "📁  Folder Summary"],
        key="report_scanner_section",
        label_visibility="collapsed",
        horizontal=True,
    )
    st.markdown("---")

    if scanner_section == "📋  Report Inventory":
        stale_months = st.slider(
            "Stale threshold (months since last run)", 1, 24, 6,
            key="report_stale_months",
        )
        show_diff_only = st.checkbox("Show stale / orphaned only", key="report_stale_only")

        if st.button("🔍  Load Reports", key="load_reports_btn"):
            with st.spinner("Loading report inventory…"):
                st.session_state["_report_df"] = _load_report_inventory()

        df: pd.DataFrame = st.session_state.get("_report_df")
        if df is None:
            st.info("Click **Load Reports** to fetch the report inventory.")
            return
        if df.empty:
            st.warning("No reports found or query unavailable.")
            return

        import pytz
        now = pd.Timestamp.now(tz=pytz.UTC)
        cutoff = now - pd.DateOffset(months=stale_months)

        df["Stale"]    = df["LastRunDate"].isna() | (df["LastRunDate"] < cutoff)
        df["Orphaned"] = ~df["OwnerActive"]

        stale_ct   = df["Stale"].sum()
        orphan_ct  = df["Orphaned"].sum()

        col_a, col_b, col_c = st.columns(3)
        col_a.metric("Total Reports", len(df))
        col_b.metric(f"Stale (>{stale_months}mo)", int(stale_ct))
        col_c.metric("Orphaned", int(orphan_ct))
        st.markdown("")

        view = df.copy()
        if show_diff_only:
            view = view[view["Stale"] | view["Orphaned"]]

        def _flag(row):
            flags = []
            if row["Stale"]:    flags.append("🟠 Stale")
            if row["Orphaned"]: flags.append("🔴 Orphaned")
            return ", ".join(flags) if flags else "✅ OK"

        view["Status"] = view.apply(_flag, axis=1)
        display_cols = ["Name", "Folder", "Owner", "LastRunDate", "CreatedDate", "Status"]
        st.dataframe(
            view[display_cols].rename(columns={
                "LastRunDate": "Last Run", "CreatedDate": "Created"
            }),
            use_container_width=True,
            hide_index=True,
        )

        if st.button("📥  Export cleanup candidates as CSV", key="export_stale_reports"):
            candidates = df[df["Stale"] | df["Orphaned"]][display_cols]
            csv_data = candidates.to_csv(index=False).encode("utf-8")
            st.download_button(
                "Download CSV",
                data=csv_data,
                file_name="stale_orphaned_reports.csv",
                mime="text/csv",
                key="download_stale_reports",
            )

    elif scanner_section == "📊  Dashboard Inventory":
        if st.button("🔍  Load Dashboards", key="load_dashboards_btn"):
            with st.spinner("Loading dashboard inventory…"):
                st.session_state["_dashboard_df"] = _load_dashboard_inventory()

        df: pd.DataFrame = st.session_state.get("_dashboard_df")
        if df is None:
            st.info("Click **Load Dashboards** to fetch the dashboard inventory.")
            return
        if df.empty:
            st.warning("No dashboards found or query unavailable.")
            return

        st.metric("Total Dashboards", len(df))
        st.markdown("")
        st.dataframe(
            df[["Title", "Folder", "RunningUser", "LastViewedDate", "CreatedDate"]].rename(
                columns={"LastViewedDate": "Last Viewed", "CreatedDate": "Created"}
            ),
            use_container_width=True,
            hide_index=True,
        )

    elif scanner_section == "📁  Folder Summary":
        stale_months = st.session_state.get("report_stale_months", 6)
        df: pd.DataFrame = st.session_state.get("_report_df")
        if df is None:
            st.info("Load the Report Inventory first to see folder summaries.")
            return

        import pytz
        now = pd.Timestamp.now(tz=pytz.UTC)
        cutoff = now - pd.DateOffset(months=stale_months)
        df["Stale"]    = df["LastRunDate"].isna() | (df["LastRunDate"] < cutoff)
        df["Orphaned"] = ~df["OwnerActive"]

        folder_summary = (
            df.groupby("Folder")
            .agg(
                Total=("Id", "count"),
                Stale=("Stale", "sum"),
                Orphaned=("Orphaned", "sum"),
            )
            .reset_index()
            .sort_values("Total", ascending=False)
        )
        folder_summary["Stale"]    = folder_summary["Stale"].astype(int)
        folder_summary["Orphaned"] = folder_summary["Orphaned"].astype(int)
        st.dataframe(folder_summary, use_container_width=True, hide_index=True)


# ══════════════════════════════════════════════════════════════════════════════
# PAGE: BULK OWNERSHIP TRANSFER  (page = "ownership_transfer")  — Brief 06
# ══════════════════════════════════════════════════════════════════════════════

# Session state key prefix
_OT = "ot_"


def _ot_state(key: str, default=None):
    full_key = _OT + key
    if full_key not in st.session_state:
        st.session_state[full_key] = default
    return st.session_state[full_key]


def _ot_set(key: str, value):
    st.session_state[_OT + key] = value


def _fetch_user_ownership_summary(user_id: str) -> dict[str, int]:
    """Count records owned by user across key objects."""
    sf = get_sf_connection()
    counts = {}
    queries = {
        "Accounts":              f"SELECT COUNT(Id) c FROM Account WHERE OwnerId = '{user_id}'",
        "Contacts":              f"SELECT COUNT(Id) c FROM Contact WHERE OwnerId = '{user_id}'",
        "Open Opportunities":    f"SELECT COUNT(Id) c FROM Opportunity WHERE OwnerId = '{user_id}' AND IsClosed = false",
        "Closed Opportunities":  f"SELECT COUNT(Id) c FROM Opportunity WHERE OwnerId = '{user_id}' AND IsClosed = true",
        "Open Cases":            f"SELECT COUNT(Id) c FROM Case WHERE OwnerId = '{user_id}' AND IsClosed = false",
        "Open Tasks":            f"SELECT COUNT(Id) c FROM Task WHERE OwnerId = '{user_id}' AND IsClosed = false",
    }
    for label, soql in queries.items():
        try:
            res = sf.query(soql)
            counts[label] = res["records"][0]["c"]
        except Exception:
            counts[label] = 0
    return counts


def _fetch_owned_records(object_name: str, user_id: str, extra_filter: str = "") -> pd.DataFrame:
    sf = get_sf_connection()
    filt = f"OwnerId = '{user_id}'"
    if extra_filter:
        filt += f" AND {extra_filter}"
    soql = f"SELECT Id, Name, OwnerId FROM {object_name} WHERE {filt} LIMIT 5000"
    try:
        result = sf.query(soql)
        rows = result.get("records", [])
        return pd.DataFrame([{"Id": r["Id"], "Name": r.get("Name", r["Id"])} for r in rows])
    except Exception:
        return pd.DataFrame()


def render_ownership_transfer_page(dry_run_mode: bool, auto_backup: bool):
    st.subheader("👤  Bulk Ownership Transfer Wizard")
    st.caption(
        "Transfer all records owned by a departing user to one or more new owners. "
        "Step through the wizard to preview before executing."
    )

    # ── Wizard step indicator ──────────────────────────────────────────────────
    step = _ot_state("step", 1)
    step_labels = ["1. Source User", "2. Target User", "3. Preview", "4. Execute"]
    col_steps = st.columns(4)
    for i, (col, label) in enumerate(zip(col_steps, step_labels), start=1):
        with col:
            color = COLOR_SUCCESS if i < step else ("#017551" if i == step else "#234035")
            st.markdown(
                f'<div style="text-align:center;padding:6px;border-radius:6px;'
                f'background:{color};color:white;font-size:0.8rem;">{label}</div>',
                unsafe_allow_html=True,
            )
    st.markdown("---")

    # ── Step 1: Select source user ─────────────────────────────────────────────
    if step == 1:
        st.subheader("Step 1 — Select source user")
        users = get_all_active_users()
        user_labels = [f"{u['Name']} ({u.get('Email', '')})" for u in users]
        user_ids    = [u["Id"] for u in users]
        sel_idx = st.selectbox(
            "Source user (the user whose records will be transferred)",
            range(len(user_labels)),
            format_func=lambda i: user_labels[i],
            key="ot_src_idx",
        )
        sel_user = users[sel_idx]

        if st.button("Load ownership summary", key="ot_load_summary"):
            with st.spinner("Counting records…"):
                summary = _fetch_user_ownership_summary(sel_user["Id"])
                _ot_set("src_user", sel_user)
                _ot_set("src_summary", summary)

        summary = _ot_state("src_summary")
        if summary:
            src = _ot_state("src_user")
            st.markdown(f"**{src['Name']}** owns:")
            cols = st.columns(3)
            for i, (label, count) in enumerate(summary.items()):
                with cols[i % 3]:
                    color = COLOR_WARNING if "Closed" in label else COLOR_SUCCESS
                    st.markdown(
                        f'<div style="background:#1a3028;border-radius:6px;padding:0.6rem 1rem;margin-bottom:0.5rem;">'
                        f'<div style="font-size:1.4rem;font-weight:700;color:{color};">{count:,}</div>'
                        f'<div style="font-size:0.75rem;color:#b8ccbf;">{label}</div>'
                        f'</div>',
                        unsafe_allow_html=True,
                    )
            if st.button("Next →", key="ot_step1_next"):
                _ot_set("step", 2)
                st.rerun()

    # ── Step 2: Select target user ─────────────────────────────────────────────
    elif step == 2:
        src = _ot_state("src_user", {})
        st.subheader(f"Step 2 — Select target user")
        st.caption(f"Records currently owned by **{src.get('Name', '?')}** will be transferred to:")
        users = get_all_active_users()
        user_labels = [f"{u['Name']} ({u.get('Email', '')})" for u in users]
        sel_idx = st.selectbox(
            "Target user",
            range(len(user_labels)),
            format_func=lambda i: user_labels[i],
            key="ot_tgt_idx",
        )
        cascade = st.checkbox(
            "Also transfer Contacts whose Account is being transferred",
            value=True,
            key="ot_cascade",
        )
        include_tasks = st.checkbox("Include open Tasks and Events", value=True, key="ot_tasks")

        col_back, col_next = st.columns([1, 5])
        with col_back:
            if st.button("← Back", key="ot_step2_back"):
                _ot_set("step", 1)
                st.rerun()
        with col_next:
            if st.button("Next →", key="ot_step2_next"):
                _ot_set("tgt_user", users[sel_idx])
                _ot_set("cascade", cascade)
                _ot_set("include_tasks", include_tasks)
                _ot_set("step", 3)
                st.rerun()

    # ── Step 3: Preview ────────────────────────────────────────────────────────
    elif step == 3:
        src = _ot_state("src_user", {})
        tgt = _ot_state("tgt_user", {})
        cascade = _ot_state("cascade", True)
        include_tasks = _ot_state("include_tasks", True)
        st.subheader("Step 3 — Preview transfer")
        st.caption(
            f"**{src.get('Name', '?')}** → **{tgt.get('Name', '?')}**. "
            "Records shown below will be updated."
        )

        if st.button("🔍  Load preview", key="ot_load_preview"):
            with st.spinner("Loading records…"):
                src_id = src["Id"]
                preview: dict[str, pd.DataFrame] = {}
                preview["Accounts"]           = _fetch_owned_records("Account", src_id)
                preview["Open Opportunities"] = _fetch_owned_records("Opportunity", src_id, "IsClosed = false")
                preview["Open Cases"]         = _fetch_owned_records("Case", src_id, "IsClosed = false")
                if cascade:
                    preview["Contacts"] = _fetch_owned_records("Contact", src_id)
                if include_tasks:
                    preview["Open Tasks"] = _fetch_owned_records("Task", src_id, "IsClosed = false")

                # Closed Opps warning
                closed_opps = _fetch_owned_records("Opportunity", src_id, "IsClosed = true")
                _ot_set("closed_opps_count", len(closed_opps))
                _ot_set("preview", preview)

        preview = _ot_state("preview")
        if preview:
            closed_count = _ot_state("closed_opps_count", 0)
            if closed_count:
                st.warning(
                    f"⚠️ {closed_count:,} closed Opportunities are excluded from the transfer "
                    "(closed deals are not typically reassigned)."
                )
            total_records = sum(len(df) for df in preview.values())
            st.markdown(f"**{total_records:,} records will be transferred.**")
            for obj_label, df in preview.items():
                with st.expander(f"{obj_label} ({len(df):,} records)"):
                    st.dataframe(df.head(10), use_container_width=True, hide_index=True)
                    if len(df) > 10:
                        st.caption(f"Showing first 10 of {len(df):,}.")

            col_back2, col_exec = st.columns([1, 5])
            with col_back2:
                if st.button("← Back", key="ot_step3_back"):
                    _ot_set("step", 2)
                    st.rerun()
            with col_exec:
                if st.button("Next →  Execute", key="ot_step3_next"):
                    _ot_set("step", 4)
                    st.rerun()
        else:
            if st.button("← Back", key="ot_step3_back_empty"):
                _ot_set("step", 2)
                st.rerun()

    # ── Step 4: Execute ────────────────────────────────────────────────────────
    elif step == 4:
        src = _ot_state("src_user", {})
        tgt = _ot_state("tgt_user", {})
        preview: dict[str, pd.DataFrame] = _ot_state("preview", {})

        st.subheader("Step 4 — Execute transfer")
        if not preview:
            st.error("No preview data. Go back and load the preview first.")
            if st.button("← Back", key="ot_step4_back_empty"):
                _ot_set("step", 3)
                st.rerun()
            return

        total_records = sum(len(df) for df in preview.values())
        st.markdown(
            f'<div class="safety-banner" style="background:#1a2a1a;border-color:{COLOR_WARNING};color:{COLOR_WARNING};">'
            f'⚠️ About to transfer {total_records:,} records from <strong>{src.get("Name","?")}</strong> '
            f'→ <strong>{tgt.get("Name","?")}</strong>.'
            f'{"<br>DRY RUN MODE — no changes will be made." if dry_run_mode else ""}'
            f'</div>',
            unsafe_allow_html=True,
        )
        st.markdown("")

        col_back3, col_go = st.columns([1, 5])
        with col_back3:
            if st.button("← Back", key="ot_step4_back"):
                _ot_set("step", 3)
                st.rerun()
        with col_go:
            go_label = "🔍  Dry Run (preview)" if dry_run_mode else "⚡  Execute Transfer"
            if st.button(go_label, key="ot_execute_btn"):
                sf = get_sf_connection()
                tgt_id = tgt["Id"]
                results_summary = []
                for obj_label, df in preview.items():
                    if df.empty:
                        continue
                    obj_map = {
                        "Accounts": "Account",
                        "Open Opportunities": "Opportunity",
                        "Open Cases": "Case",
                        "Contacts": "Contact",
                        "Open Tasks": "Task",
                    }
                    sf_obj = obj_map.get(obj_label, obj_label)
                    if auto_backup:
                        backup_records(df, "ownership_transfer", sf_obj)
                    records = [{"Id": row["Id"], "OwnerId": tgt_id} for row in df.to_dict("records")]
                    if not dry_run_mode:
                        result = execute_update(sf, sf_obj, records)
                        success = result.get("success_count", 0)
                        failed  = result.get("error_count", 0)
                        results_summary.append(f"✅ {obj_label}: {success:,} transferred, {failed:,} failed")
                    else:
                        results_summary.append(f"🔍 {obj_label}: {len(records):,} would be transferred")

                for line in results_summary:
                    st.markdown(line)

                if not dry_run_mode:
                    st.success("Transfer complete!")
                    if st.button("↩️  Start over", key="ot_reset"):
                        for key in list(st.session_state.keys()):
                            if key.startswith(_OT):
                                del st.session_state[key]
                        st.rerun()


