            {"name": "Temp/Test Flows in Prod","soql": "SELECT COUNT() FROM FlowDefinitionView WHERE IsActive = true AND (Label LIKE '%test%' OR Label LIKE '%temp%' OR Label LIKE '%delete%')", "threshold_type": "max_count", "threshold_value": 0},
